import type {ArticleSection} from '../types/philosophy';

const section=(id:string,title:string,paragraphs:string[],relatedBranchIds?:string[],relatedPhilosopherIds?:string[],relatedWorkTitles?:string[]):ArticleSection=>({id,title,paragraphs,relatedBranchIds,relatedPhilosopherIds,relatedWorkTitles});

export const ancientGreekPhilosopherArticles:Record<string,ArticleSection[]>={
  socrates:[
    section('overview','A turning point without a written doctrine',[
      'Socrates became a turning point in philosophy without writing a treatise, founding a school, or presenting a systematic account of nature. His importance lies in a distinctive combination of method and ethical example. He questioned people who claimed expertise, pressed them to explain the standards behind their judgments, and treated the condition of one’s character as more important than wealth, reputation, or even survival. Philosophy in this form was not a specialized body of information. It was a public practice of testing how a person lived and whether that life could withstand examination.',
      'The familiar picture of Socrates as merely “the man who asked questions” misses the force of those encounters. His questions exposed contradictions between a person’s confident general claims and the particular judgments they were unwilling to surrender. The resulting perplexity was not an entertaining defeat. It revealed that citizens who advised assemblies, educated the young, commanded armies, or performed religious duties might lack an account of courage, justice, virtue, or piety. Socratic inquiry therefore connected logic to moral formation and made intellectual humility a civic issue.',
      'Socrates is also a permanent historical problem. Because he wrote nothing, every account reaches him through authors with different aims. Plato makes him the central figure of philosophical dialogues; Xenophon presents a practical and morally improving teacher; Aristophanes turns him into a comic symbol of fashionable intellectual disruption; Aristotle discusses him from a later analytical distance. The “Socratic problem” is not an obstacle that can be removed once and for all. It is part of why Socrates remains philosophically productive: readers must distinguish historical reconstruction, literary portrait, and the arguments each portrait makes possible.'
    ],['ancient-greek','ethics'],['plato','aristotle'],['Apology','Memorabilia','Clouds']),
    section('athens','Athens, democracy, war, and public argument',[
      'Socrates lived through the height and crisis of fifth-century BCE Athens. The city’s democracy depended on citizens speaking and judging in assemblies and courts; political influence therefore required the ability to persuade. Athens also became a center for traveling teachers, intellectual experiment, drama, history, medicine, and debate about law and nature. The sophists taught rhetoric and civic competence for fees, often examining how custom varied among communities and how arguments could be made effective. In such a setting, the difference between persuasive success and genuine knowledge became an urgent political question.',
      'The Peloponnesian War destabilized Athenian confidence. Military disaster, plague, faction, oligarchic coups, and eventual defeat made questions about leadership and civic virtue concrete. Socrates served as a hoplite and was remembered for endurance and courage, yet several people associated with him became notorious political figures. Alcibiades repeatedly shifted allegiance, while Critias became a leader of the violent Thirty Tyrants. These associations did not prove Socrates responsible for their actions, but they shaped the atmosphere in which Athenians judged a teacher who publicly embarrassed prominent citizens and questioned conventional success.',
      'Socrates’ relationship to democracy is therefore difficult to summarize. He criticized collective decisions made without knowledge and compared political expertise to crafts that require training. At the same time, Plato’s Apology presents him refusing to participate in illegal actions under both democratic and oligarchic governments. He did not offer a democratic theory, but his practice required open conversation, reasons, and the possibility that status could be challenged. The tension between criticism of popular judgment and commitment to accountable speech remains central to his political significance.'
    ],['political-philosophy','ancient-greek'],['protagoras','gorgias','plato'],['Apology','Crito']),
    section('sources','The sources and the historical Socrates',[
      'Plato’s dialogues are the richest source, but they cannot be read as transcripts. In works often considered early, Socrates commonly examines definitions and disclaims wisdom. In other dialogues he presents elaborate metaphysical, psychological, and political arguments that may reflect Plato’s developing philosophy. Even when a dialogue preserves historically plausible Socratic concerns, its setting, sequence, and language have been composed to produce a philosophical effect. The literary Socrates is evidence for the historical Socrates and also a major creation in his own right.',
      'Xenophon’s Socratic writings emphasize usefulness, self-control, piety, friendship, household management, and practical advice. His Socrates often looks more conventionally improving than Plato’s disruptive examiner. Aristophanes’ Clouds, performed while Socrates was alive, combines him with natural philosophers and sophists in a comic school where weaker arguments defeat stronger ones. The caricature is not reliable biography, but it shows that Socrates could be perceived as part of a troubling intellectual culture that unsettled religion, language, and family authority.',
      'Aristotle, born after Socrates’ death, distinguishes Socrates from Plato by attributing to Socrates inductive arguments and the search for universal definitions while denying that he separated universals as Forms. This report strongly influenced modern reconstructions, but Aristotle interprets predecessors through his own conceptual framework. Historians compare these witnesses, seek points of convergence, and use chronology cautiously. No method yields a neutral Socrates behind the texts; responsible interpretation states which portrait is under discussion and how much historical confidence it can bear.'
    ],['ancient-greek','platonism'],['plato','aristotle'],['Apology','Memorabilia','Clouds']),
    section('elenchus','Elenchus, definition, and productive perplexity',[
      'The Socratic elenchus is a form of testing through question and answer. An interlocutor proposes a claim, usually with confidence; Socrates secures further commitments; those commitments prove inconsistent with the original claim; and the speaker must revise the position or acknowledge perplexity. The exchange is not a formal algorithm, and dialogues vary in structure. Its philosophical importance lies in making a person answerable to the connections among their own judgments. Refutation does not automatically establish the opposite conclusion, but it removes a false confidence that blocks inquiry.',
      'Definitions matter because Socrates repeatedly asks what courage, piety, justice, moderation, or virtue itself is. Listing examples does not yet explain what makes each example an instance of the same thing. A successful account should guide judgment across cases and survive counterexample. This search helps turn ethical discussion from appeals to tradition or reputation toward reasons that can be examined. Aristotle later credits Socrates with the pursuit of universal definitions, although the dialogues often end before finding one.',
      'Aporia, the perplexity produced by failed answers, is therefore an achievement rather than an empty conclusion. Someone who discovers that they cannot explain a value may be better positioned than someone whose certainty has never been tested. Yet the elenchus also raises questions. Does contradiction show that a belief is false or only that a set of beliefs is inconsistent? Does Socrates conceal commitments while claiming ignorance? Can repeated humiliation educate, or does it provoke defensiveness? Plato’s dialogues dramatize these risks instead of presenting questioning as an automatically benevolent technique.'
    ],['logic','ethics','epistemology'],['plato'],['Euthyphro','Laches','Charmides']),
    section('virtue-knowledge','Virtue, knowledge, and care of the soul',[
      'Socratic ethics links wrongdoing closely to ignorance. In several Platonic dialogues, Socrates argues that people desire what they take to be good and act badly because they misunderstand where their good lies. This position, often called Socratic intellectualism, does not mean that factual information alone makes a person virtuous. The relevant knowledge concerns value, motivation, and the ordering of a life. To know the good adequately would be to understand why apparent advantages such as wealth or power can damage the person who uses them unjustly.',
      'Care of the soul names the practical center of this ethics. Socrates urges citizens to care less about possessions and reputation than about becoming as good and wise as possible. “Soul” here should not be reduced to a later doctrine of an immortal substance. It names the condition of the person as an agent capable of justice, understanding, and self-examination. The claim that it is worse to commit injustice than to suffer it follows from this priority: external harm can be severe, but wrongdoing corrupts the agent’s own capacity to live well.',
      'This view creates a demanding relation between philosophy and ordinary choice. If virtue is tied to knowledge, moral education must change judgment rather than merely enforce compliance. Yet experience appears to show people acting against what they know to be best. Aristotle later develops a more complex account of weakness of will, habituation, and emotion partly in response to this difficulty. The Socratic thesis remains valuable because it asks how far wrongdoing depends on distorted descriptions: people often pursue domination, revenge, or status because they interpret them as goods.'
    ],['ethics','virtue-ethics'],['plato','aristotle'],['Apology','Gorgias','Protagoras']),
    section('irony-ignorance','Irony, ignorance, and the examined life',[
      'Socratic ignorance is not a simple claim to know nothing. In the Apology, the Delphic oracle reportedly declares that no one is wiser than Socrates. Socrates interprets the message by examining people reputed to be wise and discovering that they claim knowledge they cannot defend. His comparative wisdom consists in not taking himself to know what he does not know. At the same time, he speaks with striking confidence about duties such as refusing injustice and continuing philosophical examination. The boundary between his ignorance and his ethical commitments is a major interpretive problem.',
      'Socratic irony contributes to that problem. He often presents himself as an eager learner and praises an interlocutor’s expertise before exposing its weakness. The performance can invite cooperation, protect inquiry from direct confrontation, or reveal a speaker’s vanity. It can also look manipulative. Because Socrates’ tone is mediated by literary texts, readers must decide when professions of ignorance are sincere, strategic, humorous, or several of these at once.',
      'The examined life is not endless self-absorption. Socrates examines himself through conversation with others and treats beliefs as answerable to shared reasons. Examination has an ethical aim: to reduce the distance between what a person praises and how that person acts. It also has a political cost. Publicly revealing that influential citizens cannot explain their claims creates resentment, particularly when young observers enjoy the spectacle of refutation without adopting its discipline. Socrates’ life shows why a practice devoted to accountability can be experienced as an attack.'
    ],['ethics','epistemology'],['plato'],['Apology']),
    section('sophists','Socrates and the sophists',[
      'Ancient and modern accounts often contrast Socrates sharply with the sophists. Unlike traveling professional educators, he did not advertise a curriculum or charge fees. He denied possessing teachable wisdom and focused on care of the soul rather than training for political success. Plato frequently uses Socrates to challenge sophistic claims about rhetoric and virtue, especially when persuasion is detached from knowledge of what is just or good.',
      'The contrast is real but incomplete. Socrates and the sophists shared a turn toward human affairs, language, education, and public argument. Both could appear to conservative Athenians as intellectuals who unsettled inherited beliefs. Individual sophists also differed greatly from one another; treating them as a single cynical movement repeats Plato’s polemical framing. Protagoras’ concern with civic education and Gorgias’ analysis of speech raise serious philosophical questions rather than merely providing targets for Socrates.',
      'The deepest disagreement concerns what education promises. A rhetorician may enable a citizen to prevail in assemblies and courts, but Socrates asks whether success without knowledge benefits the speaker. If rhetoric is a power to persuade regardless of truth, it can magnify ignorance. If civic virtue can be taught, the teacher must explain what virtue is and how instruction changes character. These challenges transform educational practice into a philosophical problem about expertise, value, and responsibility.'
    ],['philosophy-of-language','political-philosophy','ancient-greek'],['protagoras','gorgias','plato'],['Protagoras','Gorgias','Clouds']),
    section('trial','Trial, conviction, and execution',[
      'In 399 BCE, Socrates was prosecuted for not recognizing the gods of the city, introducing new divine matters, and corrupting the young. The surviving evidence does not let historians reduce the trial to one motive. Religious concerns, his public reputation, the resentment generated by questioning, and the recent political trauma surrounding figures associated with him likely formed part of the context. The formal procedure required jurors first to decide guilt and then choose between proposed penalties.',
      'Plato’s Apology portrays Socrates refusing the conventional strategy of emotional pleading. He defends his mission as a service to the city, compares himself to a gadfly awakening a large horse, and insists that fear of death should not override a duty one judges just. After conviction, his provocative discussion of penalty may have contributed to the death sentence. The speech makes the trial a test of whether philosophy can remain faithful to its standards when persuasion and survival pull in another direction.',
      'The Crito places a different pressure on the same life. Friends offer escape, but Socrates argues that one must not answer injustice with injustice and stages a speech by the Laws of Athens. Readers dispute whether this commits him to near-absolute obedience or expresses obligations arising from a specific life under a legal order. In the Phaedo, Plato transforms the final day into a philosophical scene about death and soul. These portraits do not simply report an execution; they make Socrates’ death an argument about integrity, law, fear, and the unity of philosophy with action.'
    ],['political-philosophy','ethics'],['plato'],['Apology','Crito','Phaedo']),
    section('portraits','Four philosophical portraits',[
      'The Euthyphro stages Socrates outside the court as he prepares to answer charges of impiety. His conversation with a confident religious expert asks whether an action is pious because the gods love it or the gods love it because it is pious. The dilemma separates moral standards from mere command and exposes the difficulty of defining piety. Dramatically, a man prosecuted for impiety appears more careful about religious understanding than the accuser who claims expertise.',
      'The Apology presents Socrates as a public examiner whose refusal to abandon philosophy is inseparable from his defense. The Crito tests that stance against friendship, family obligations, legal injustice, and the opportunity to escape. The Phaedo presents a more metaphysical Socrates discussing immortality and Forms, which may reveal Plato’s philosophical development as much as the historical Socrates. Read together, the works construct an ethical sequence: accusation, defense, temptation to escape, and death.',
      'Xenophon’s Memorabilia supplies another portrait, defending Socrates against the charge of corruption by showing his usefulness and self-control. Aristophanes’ Clouds supplies the hostile comic image of an intellectual whose techniques disrupt household and civic order. The differences among these portraits are not noise surrounding a recoverable set of doctrines. They show how Socrates rapidly became a contested symbol of philosophy itself: liberating examiner, practical moralist, dangerous sophist, or literary vehicle for a successor’s ideas.'
    ],['ethics','philosophy-of-religion'],['plato'],['Euthyphro','Apology','Crito','Phaedo']),
    section('legacy','Schools, methods, and later moral philosophy',[
      'Plato makes Socrates the dramatic center of a philosophy that eventually extends far beyond what can confidently be attributed to the historical figure. Aristotle inherits the Socratic demand for definitions and ethical explanation while criticizing the identification of virtue with knowledge. Other followers emphasize different aspects. Antisthenes and the Cynic tradition radicalize independence from convention and external goods. The Cyrenaics develop a hedonistic direction. These competing inheritances show that Socrates supplied a model of philosophical life flexible enough to authorize sharply different schools.',
      'Stoics understand Socrates as an exemplary sage whose character remains free because genuine good lies in virtue rather than fortune. Skeptical traditions inherit the discipline of exposing unsupported certainty and suspending premature judgment. Later religious and moral writers repeatedly return to Socrates as a virtuous non-Christian, a martyr to reason, or a challenge to complacent orthodoxy. Modern philosophy uses “Socratic method” for forms of questioning in education, law, and therapy, though these practices can become mechanical if separated from the ethical demand to examine one’s own assumptions.',
      'Socrates’ most durable influence is the claim that philosophy changes the standing of the person who speaks. An argument about justice cannot be insulated from whether the speaker acts justly; a claim to expertise invites examination; acknowledged ignorance can be intellectually superior to confident error. This legacy is powerful and dangerous. It can encourage humility and accountability, but a self-appointed examiner can also avoid scrutiny by casting every challenge as evidence of others’ confusion. A genuinely Socratic practice must direct questioning toward itself.'
    ],['cynicism','stoicism','skepticism','ethics'],['plato','aristotle','antisthenes','epictetus'],['Apology','Memorabilia']),
    section('disputes-reading','Interpretive disputes and how to read Socrates',[
      'Interpreters disagree about whether Socrates held positive doctrines or practiced a mainly negative method. His recurring commitments about virtue, injustice, and care of the soul suggest more than empty questioning, yet his professions of ignorance resist construction of a complete system. Scholars also dispute Socratic intellectualism: whether he literally denies weakness of will, whether virtue is one kind of knowledge, and whether his ethical confidence is compatible with his epistemic humility.',
      'Political interpretations range from Socrates as democratic critic to opponent of democracy or principled dissident. The evidence supports tensions rather than a clean label. He submits to trial and remains in Athens, yet openly criticizes mass judgment and refuses illegal commands. His associations include democrats, oligarchs, and politically disastrous students. The historical question of responsibility cannot be settled by admiration for his death or by guilt through association.',
      'Begin reading with Plato’s Apology, then pair it with the Euthyphro and Crito. These works make questioning, piety, law, and ethical consistency visible without requiring prior metaphysics. Read Xenophon and selections from Aristophanes to encounter competing portraits before assuming Plato provides neutral access. When moving to the Phaedo, distinguish the exemplary death scene from arguments likely shaped by Plato’s own project. Socrates rewards comparative reading because no single text can close the problem he represents.'
    ],['ethics','political-philosophy','ancient-greek'],['plato','xenophon'],['Apology','Euthyphro','Crito','Phaedo','Memorabilia','Clouds'])
  ],
  aristotle:[
    section('overview','A system of distinct but connected inquiries',[
      'Aristotle’s surviving works range across logic, metaphysics, physics, biology, psychology, ethics, politics, rhetoric, poetry, and the organization of scientific knowledge. Calling him a system-builder does not mean that every subject is forced into one formula. He repeatedly asks what kind of precision a subject permits and develops methods suited to different domains. Mathematical demonstration, biological observation, practical judgment, and political comparison answer different questions, even while they share a commitment to identifying causes and making phenomena intelligible.',
      'His central concepts connect these inquiries. Form and matter explain how concrete beings are structured; potentiality and actuality explain change and development; four kinds of cause distinguish different answers to “why?”; function and activity connect the nature of a capacity to its fulfillment. These tools are not isolated vocabulary items. They allow Aristotle to explain how living things persist through change, how knowledge differs from true belief, how character becomes stable through practice, and how institutions shape human flourishing.',
      'Aristotle’s authority later became immense, but reading him as an unquestioned master distorts both his work and its history. His texts argue with predecessors, classify disagreements, and revise positions. Later Greek, Arabic, Jewish, Latin, Byzantine, and modern readers transformed his philosophy for their own problems. Some of his empirical claims and political judgments are false or deeply objectionable. His continuing importance lies in the explanatory architecture he built and in the precision with which later thinkers can criticize it.'
    ],['aristotelianism','metaphysics','logic','ethics'],['plato'],['Metaphysics','Nicomachean Ethics']),
    section('life-academy','Plato, the Academy, and the Lyceum',[
      'Aristotle was born in Stagira in northern Greece in 384 BCE. His father was associated with the Macedonian court as a physician, a background sometimes connected to Aristotle’s sustained interest in living beings, although direct influence is difficult to establish. Around the age of seventeen he entered Plato’s Academy in Athens and remained there for roughly two decades. This long membership matters: Aristotle’s philosophy is not a rejection of Plato from outside but an internal transformation of questions learned in the Academy.',
      'After Plato’s death, Aristotle spent time in Assos and Lesbos, where his biological investigations likely developed through close observation of marine and terrestrial life. He later tutored the young Alexander of Macedon, though the extent and philosophical significance of that relationship are uncertain. Returning to Athens, Aristotle founded the Lyceum. The school collected constitutions, studied animals, organized earlier arguments, and supported collaborative research. It gave systematic inquiry an empirical and institutional dimension distinct from the Academy while retaining philosophy’s broad scope.',
      'Aristotle departed from Plato without abandoning the Platonic demand for intelligibility. He criticizes separately existing Forms because, in his view, they fail to explain change and the being of concrete substances. Yet he keeps form as an explanatory principle within things and continues to ask how knowledge reaches universality. The contrast is therefore not simply Plato the abstract idealist against Aristotle the practical observer. Aristotle joins observation to conceptual structure and often criticizes predecessors precisely because he shares their ambition to explain why things are as they are.'
    ],['platonism','aristotelianism','ancient-greek'],['plato','alexander'],['Metaphysics','History of Animals']),
    section('logic-science','Logic, demonstration, and scientific knowledge',[
      'The works later grouped as the Organon examine terms, propositions, valid inference, demonstration, and dialectical argument. In the Categories, Aristotle distinguishes ways in which predicates are said and asks which beings are primary. In On Interpretation, he analyzes affirmation, negation, contradiction, and future contingents. The Prior Analytics develops the syllogistic, a systematic account of how conclusions follow from premises because of their form. This achievement provided the dominant framework of formal logic for many centuries.',
      'The Posterior Analytics asks what scientific knowledge requires. Demonstration does more than show that a conclusion follows; it explains why the conclusion is true through premises that identify appropriate causes. A geometer who can calculate a result without understanding its proof does not yet possess the fullest knowledge. Aristotle also recognizes that demonstrations cannot proceed from demonstrated premises without end. Sciences require principles grasped through a development from perception, memory, experience, and intellectual understanding.',
      'Dialectic differs from demonstration. It reasons from reputable or widely accepted opinions and tests positions through questions, objections, and distinctions. Dialectical inquiry can expose difficulties, compare rival accounts, and help identify first principles, even when it does not yield scientific certainty. Aristotle’s own treatises often operate in this exploratory mode: they survey what predecessors said, identify puzzles, preserve insights on multiple sides, and seek an account capable of explaining the strongest evidence.'
    ],['logic','epistemology','aristotelianism'],[],['Categories','On Interpretation','Prior Analytics','Posterior Analytics','Topics']),
    section('substance','Substance, form, matter, and being',[
      'Aristotle’s metaphysics begins from the observation that “being” is said in several ways. A substance, a quality, a relation, and an action all are, but not in the same manner. Primary substances are concrete beings such as this person or this horse, which can bear properties and persist through change. The question of substance becomes difficult when Aristotle asks what makes a concrete thing the unified thing it is: its matter, its form, the composite, or some relation among them.',
      'Hylomorphism, the account of form and matter, answers by refusing two reductions. A living organism is not merely an arrangement imposed on otherwise complete matter, nor is its form a separately existing duplicate. Matter is what is organized and capable of taking form; form is the actuality and intelligible organization through which the thing performs characteristic activities. The distinction is relative to explanation: bronze can be matter for a statue while already being a structured material with its own properties.',
      'The Metaphysics develops these problems through arguments that do not always fit neatly together. Substance may be approached through subjecthood, essence, form, or actuality. Aristotle’s account of a first unmoved mover introduces a highest actuality that explains eternal motion as an object of desire and thought rather than as an efficient push at the beginning of time. Interpreters dispute the unity of these books and whether Aristotle’s metaphysics culminates in theology, ontology, substance theory, or a coordinated inquiry into all three.'
    ],['metaphysics','ontology','aristotelianism'],['plato'],['Categories','Metaphysics']),
    section('change-causes','Change, potentiality, actuality, and four causes',[
      'Parmenidean arguments had made change philosophically difficult: if what is comes from what is not, how can change avoid arising from nothing? Aristotle distinguishes different senses of being and not-being. A seed is not actually a tree, but it can be a tree; a person who knows a language may not be speaking it now, yet possesses the capacity. Potentiality and actuality make change intelligible as the realization of a structured capacity rather than the emergence of being from absolute nonbeing.',
      'Aristotle’s four causes distinguish explanatory questions often compressed into one. The material cause identifies what something is made from; the formal cause identifies its organization or essence; the efficient cause identifies the source of change; the final cause identifies the end or activity for the sake of which a process occurs. A house can be explained through bricks, plan, builders, and purpose. These causes can cooperate rather than compete, and different sciences may emphasize different ones.',
      'Final causation is especially controversial. Aristotle frequently explains organs and developmental processes through what they characteristically do for an organism. This does not mean that every natural event consciously plans a goal. It means that regular development and functional organization may be understood through the mature activities toward which capacities are ordered. Modern mechanical science rejected many Aristotelian applications, but contemporary philosophy of biology still debates function, organization, and whether purposive language can be naturalized without becoming empty.'
    ],['metaphysics','philosophy-of-science'],[],['Physics','Metaphysics']),
    section('nature-biology','Nature, biology, and empirical research',[
      'For Aristotle, natural beings have internal principles of change and rest. A plant grows through its own organization in a way a bed does not; an animal moves, perceives, and reproduces through capacities belonging to its form of life. Physics therefore studies motion, place, time, continuity, and natural explanation, while biological works investigate the differentiated activities of living beings. Aristotle’s science is qualitative and teleological, but it is also sustained by observation, comparison, dissection, and the collection of reports.',
      'The biological corpus describes animal parts, generation, movement, habitats, and differences among species. Aristotle looks for correlations between structure and function and tries to explain why organisms possess certain features. Many observations are perceptive; others are mistaken, constrained by limited instruments, inherited assumptions, and uneven evidence. His hierarchy of living beings and claims about sex difference also encode prejudices that later traditions amplified.',
      'Aristotle’s scientific importance does not depend on treating his conclusions as current biology. He models a form of inquiry that begins from phenomena, organizes differences, and seeks causes appropriate to the subject. Modern science displaced his physics and cosmology, especially through mathematical mechanics and experiment, yet questions about explanation, classification, organism, and function continue to engage Aristotelian concepts. The history is one of criticism and selective recovery, not simple victory over an unscientific past.'
    ],['philosophy-of-science','aristotelianism'],[],['Physics','History of Animals','Parts of Animals','Generation of Animals']),
    section('soul','Soul, perception, and living beings',[
      'In De Anima, soul is the form or first actuality of a living body capable of life. This definition rejects the picture of soul as merely a ghost inhabiting an otherwise complete machine. Nutrition, growth, perception, desire, movement, and thought are capacities through which kinds of living beings are organized. Plants possess nutritive capacities; animals add perception and desire; human beings possess rational capacities while retaining the others.',
      'Perception occurs when a sense organ receives the perceptible form of an object without receiving its matter. The eye does not become the colored object physically, but its activity becomes informed by color. Aristotle’s account tries to preserve the world-directedness of perception while explaining it as a natural capacity of embodied organisms. Imagination, memory, desire, and movement connect perception to action, producing a psychology integrated with biology rather than isolated from it.',
      'The account of intellect is more difficult. Aristotle distinguishes a receptive intellect from an active or productive intellect in a brief passage that generated centuries of dispute. Is the active intellect part of an individual human soul, a separate intellect shared by all, or a divine principle? Alexander of Aphrodisias, Avicenna, Averroes, Aquinas, and many others answer differently. The obscurity of the text made Aristotelian psychology a central meeting point for metaphysics, theology, and theories of personal immortality.'
    ],['philosophy-of-mind','aristotelianism'],['avicenna','averroes','aquinas'],['De Anima']),
    section('ethics','Flourishing, virtue, and practical wisdom',[
      'The Nicomachean Ethics begins from the claim that actions aim at goods and asks whether there is an ultimate end chosen for itself. Aristotle identifies eudaimonia, often translated as flourishing or happiness, with excellent activity across a complete life. Flourishing is not a passing feeling. It involves exercising human capacities well, especially rational and social capacities, while also requiring friendships, institutions, and sufficient external goods.',
      'Ethical virtue is formed through habituation. People become just by doing just actions, but mere repetition is not enough: mature virtue includes acting knowingly, choosing the action for its own sake, and doing so from a stable character. The doctrine of the mean says that virtue often finds what is appropriate between opposed errors relative to the situation. It is not a mathematical compromise. Courage, for example, responds rightly to fear and confidence; the appropriate response may be demanding and far from average behavior.',
      'Practical wisdom, or phronesis, enables a person to deliberate well about action. Universal principles cannot mechanically determine every concrete choice because ethically relevant circumstances vary. Practical wisdom perceives what matters, connects means to worthwhile ends, and develops with character. Aristotle’s ethics therefore joins reason, emotion, habit, and social formation. Critics ask whether its account of flourishing is too dependent on privileged Greek citizenship and whether its picture of function can support modern pluralism, but the framework remains central to virtue ethics.'
    ],['ethics','virtue-ethics'],[],['Nicomachean Ethics','Eudemian Ethics']),
    section('politics','Politics, citizenship, and exclusion',[
      'Aristotle treats human beings as political animals because speech and practical reason enable communities to deliberate about justice and advantage. The polis is not merely a security arrangement; it provides conditions in which citizens can act and flourish together. The Politics compares constitutions, distinguishes correct and deviant forms, examines stability and revolution, and asks how education should support a regime. Aristotle’s empirical collection of constitutions informs an analysis more comparative than Plato’s ideal construction.',
      'Citizenship, however, is defined through participation in deliberative and judicial office, and Aristotle excludes many residents from that standing. He defends natural slavery, restricts citizenship by gender and labor, and treats the leisure of some as dependent on the work of others. These positions are not incidental details to be ignored when extracting a neutral theory of civic flourishing. They reveal how claims about nature and function can legitimize inherited hierarchy.',
      'The Politics is valuable partly because it makes these connections visible. Institutions shape character; distributions of wealth affect stability; a constitution embodies a conception of who counts and what the community is for. Modern readers can use Aristotle’s analysis of civic formation and regime incentives while rejecting his exclusions. Doing so requires more than announcing that he was a man of his time. It requires examining where his explanatory concepts accurately diagnose political life and where they convert domination into alleged natural order.'
    ],['political-philosophy','ethics'],['plato'],['Politics','Constitution of the Athenians']),
    section('rhetoric-poetics','Rhetoric, tragedy, and forms of understanding',[
      'The Rhetoric studies persuasion as a practical art. Aristotle distinguishes appeals grounded in the speaker’s character, the audience’s emotions, and the argument itself. Because political and legal decisions concern matters that cannot always be demonstrated with scientific certainty, rhetoric is not simply corrupted logic. It can organize reasons for audiences who must judge under practical conditions. Yet the same understanding can be used manipulatively, making ethical character and institutional context essential.',
      'The Poetics analyzes tragedy through plot, character, diction, thought, spectacle, and song, giving plot a central role. Tragedy represents serious action and produces understanding through the structured reversal, recognition, and suffering of a plot. Aristotle’s concept of catharsis remains disputed, but his larger move is clear: poetry can disclose general patterns of action and consequence rather than merely copy particular events. In this respect poetry may be more philosophical than history, which reports what happened.',
      'These works demonstrate the breadth of Aristotelian explanation. A speech and a tragedy are human artifacts, but they possess forms, functions, parts, and characteristic effects open to systematic analysis. Aristotle neither reduces art and persuasion to moral instruction nor isolates them from ethical and political life. His categories became foundational for later rhetorical and literary criticism, even where modern genres and aesthetic theories exceed them.'
    ],['aesthetics','philosophy-of-language','political-philosophy'],[],['Rhetoric','Poetics']),
    section('transmission','Transmission, transformation, and modern criticism',[
      'Aristotle’s texts reached later readers through complex transmission. Late antique commentators organized, interpreted, and debated the corpus. Syriac and Arabic translation movements made Aristotle and his commentators central to philosophy in Islamic worlds. Al-Farabi, Avicenna, Averroes, and others did not merely preserve him; they reconstructed logic, metaphysics, psychology, and political philosophy. Latin translations and commentaries later transformed European scholasticism, especially through debates over intellect, causation, nature, and theology.',
      'Aquinas developed a Christian Aristotelian synthesis while modifying Aristotle on creation, divine being, and the human person. Renaissance scholars recovered Greek texts and challenged inherited readings. Early modern science rejected Aristotelian cosmology and much of its physics as mathematical mechanics and experimental methods developed. That rejection often defined “Aristotelian” as a symbol of scholastic obstruction, obscuring the empirical and argumentative dimensions of Aristotle’s own work.',
      'Contemporary philosophy selectively revives Aristotelian ideas. Virtue ethics returns to character, habituation, and flourishing; metaphysicians examine powers, substance, form, and grounding; philosophers of biology reconsider organism and function; political theorists study civic formation and constitutions. These recoveries are strongest when they neither restore Aristotle wholesale nor treat modern terminology as identical to his. Aristotelianism remains a living tradition because its concepts can be transformed under criticism.'
    ],['aristotelianism','medieval-scholasticism','islamic-philosophy'],['avicenna','averroes','aquinas'],['Metaphysics','De Anima','Nicomachean Ethics']),
    section('disputes-reading','Interpretive disputes and how to read Aristotle',[
      'Aristotle’s surviving treatises are compressed and may derive from teaching materials assembled or edited across time. Their organization, chronology, and relation to lost published dialogues remain disputed. Scholars ask whether Aristotle moved from an early Platonism toward empirical independence or whether his mature work contains several approaches without a simple developmental sequence. Apparent contradictions may reflect development, different levels of analysis, or unresolved tensions.',
      'Major interpretive disputes concern the unity of metaphysics, the status of form, the meaning of final causation, the relation between the Nicomachean and Eudemian Ethics, and the nature of intellect. Common misunderstandings simplify his views: the mean is not mediocrity; teleology is not always conscious design; form is not merely visible shape; and observation does not make Aristotle a modern empiricist. His systematic vocabulary must be reconstructed through the problems it was designed to solve.',
      'A beginner can start with the Nicomachean Ethics, especially Books I, II, III, VI, VIII, and X, because its questions connect readily to life while displaying Aristotle’s method. The Poetics offers a short example of analyzing a practice through parts and function. De Anima introduces hylomorphism through living beings. The Physics and Metaphysics are best approached with guidance and selected books. Read slowly enough to distinguish Aristotle’s own proposal from the predecessor views and puzzles he carefully stages before it.'
    ],['aristotelianism','metaphysics','ethics'],['plato'],['Nicomachean Ethics','Poetics','De Anima','Physics','Metaphysics'])
  ]
};

export const ancientGreekBranchArticles:Record<string,ArticleSection[]>={
  'ancient-greek':[
    section('overview','Not one school, but an expanding argument',[
      'Ancient Greek philosophy is not a single doctrine or a straight path from myth to reason. It is a long, internally diverse conversation conducted across Greek-speaking communities from the archaic period through the Hellenistic and Roman worlds. Its participants disagree about what exists, how change is possible, what knowledge requires, how language persuades, what makes a life good, and which political arrangements deserve loyalty. The category includes natural investigators, mathematicians, sophists, Socratics, systematic schools, skeptics, and philosophers who treated daily practice as more important than theory.',
      'The tradition’s later prestige can hide how experimental it was. Early thinkers wrote poems, maxims, prose treatises, speeches, dialogues, lecture materials, and technical investigations. Much survives only through fragments quoted by critics or reports written centuries later. “Greek philosophy” is therefore partly a modern reconstruction from uneven evidence. Familiar canonical figures mattered enormously, but they worked within networks that included medicine, law, drama, religious practice, mathematics, craft knowledge, and political conflict.',
      'What unifies the field is not an ethnic essence or exclusive invention of rational thought. Greek-speaking thinkers drew from Mediterranean and Near Eastern knowledge, and other civilizations possessed sophisticated traditions of inquiry. A more defensible unity lies in recurring arguments and institutions: public debate, competing schools, systematic questioning of nature and convention, and the preservation of disagreements as material for further reasoning.'
    ],['ancient-greek','metaphysics','ethics'],['socrates','plato','aristotle'],[]),
    section('background','Poetry, religion, medicine, mathematics, and the polis',[
      'Greek philosophy develops against a background of epic poetry, ritual, law, colonization, trade, and political experiment. Homeric and Hesiodic poems supplied stories about gods, justice, conflict, fate, and human excellence. Philosophers did not simply discard this inheritance. They criticized, allegorized, transformed, and competed with poetic authority. When Xenophanes objects that humans depict gods in their own image, he is participating in a debate about representation and piety made possible by the cultural power of poetry.',
      'Medicine encouraged explanations that connected symptoms, environments, diet, and bodily processes without reducing illness to divine punishment. Mathematics provided models of proof, proportion, and intelligible order. Political life in cities made speech consequential: citizens argued in assemblies and courts, laws differed among communities, and constitutional changes raised questions about nature and convention. Drama publicly examined responsibility, conflict, and the limits of human knowledge. These practices formed an intellectual ecology in which philosophical questions could become distinct without becoming isolated.',
      'The word philosophia came to name a love or pursuit of wisdom, but boundaries remained fluid. A natural philosopher might study cosmology, meteorology, biology, ethics, and theology together. A sophist could analyze language, teach civic competence, and question standards of truth. Plato and Aristotle later organized predecessors into histories that served their own projects. Reading ancient Greek philosophy requires noticing these retrospective classifications while allowing earlier thinkers to remain stranger and less specialized than modern academic fields.'
    ],['ancient-greek','philosophy-of-science','political-philosophy'],['xenophanes','protagoras'],[]),
    section('milesians','Milesians and natural explanation',[
      'Thales, Anaximander, and Anaximenes are conventionally described as the first Greek philosophers because they sought general explanations of the cosmos through principles within nature. The evidence is late and fragmentary, so claims about their exact arguments require caution. Thales is associated with water as a first principle; Anaximander with the indefinite or boundless from which worlds emerge; Anaximenes with air transformed through rarefaction and condensation. Their importance does not lie in guessing the correct modern substance but in asking how diverse phenomena could belong to an intelligible order.',
      'Anaximander’s surviving fragment describes things paying justice and penalty to one another according to the order of time. The language joins natural process to a vocabulary of justice without simply personifying weather or matter. It suggests an attempt to explain generation and destruction through a regulated balance. Anaximenes offers a more concrete mechanism by connecting qualitative differences to changes in density. These proposals show early natural explanation developing through criticism: a successor preserves the search for unity while revising what the principle must be and how it explains difference.',
      'Calling these thinkers scientists or materialists can mislead. Their cosmologies include theological, ethical, and speculative dimensions, and they lacked modern experimental institutions. Yet they establish questions that remain philosophical: what counts as an explanation, whether plurality depends on unity, and how change can be lawful rather than arbitrary. Later thinkers inherit these problems even when they reject the Milesian answers.'
    ],['metaphysics','philosophy-of-science'],['thales','anaximander','anaximenes'],[]),
    section('pythagorean-eleatic','Mathematical order, flux, and being',[
      'Pythagorean traditions connected number, harmony, cosmology, communal discipline, and the fate of the soul. The historical Pythagoras is difficult to separate from later legend, and Pythagorean positions changed across generations. Their lasting philosophical contribution was not merely the claim that everything is number. They explored how ratios and limits make order intelligible, especially in music and cosmology, and treated philosophical understanding as part of a transformed way of life.',
      'Heraclitus emphasizes change, opposition, and logos. His compressed fragments resist a simple doctrine that everything merely flows. The world displays tensions whose opposition belongs to an ordered whole; understanding requires learning to hear the common logos rather than treating private perspective as sufficient. Parmenides presents a radical challenge in poetic form: rigorous thought cannot think what is not, so being cannot come from nonbeing, perish into it, or possess the divisions and changes ordinary experience reports.',
      'The conflict between becoming and being reorganizes Greek philosophy. If Parmenides is right, ordinary explanations of change are incoherent. If Heraclitean change is fundamental, stable knowledge becomes difficult. Later pluralists, atomists, Plato, and Aristotle all answer this pressure. Zeno of Elea’s paradoxes defend Eleatic reasoning by showing that common assumptions about motion and plurality generate contradictions. These arguments make the relation between reason and appearance a central philosophical problem.'
    ],['metaphysics','logic'],['pythagoras','heraclitus','parmenides','zeno-elea'],[]),
    section('pluralists-atomists','Pluralists and atomists answer the problem of change',[
      'Empedocles, Anaxagoras, and the atomists accept much of the Eleatic challenge while trying to preserve the reality of change. They deny that basic being comes into or passes out of existence. Instead, observable generation and destruction result from the mixture, separation, or rearrangement of enduring constituents. This strategy distinguishes fundamental reality from the changing structures it composes, creating a pattern that recurs throughout metaphysics and science.',
      'Empedocles explains change through four roots—earth, air, fire, and water—combined and separated by Love and Strife. His cosmology, religious poetry, and account of purification belong together more closely than a modern division between science and spirituality suggests. Anaxagoras proposes that everything contains portions of everything and introduces nous, mind, as the ordering cause of cosmic rotation. Socrates in Plato’s Phaedo later recalls being excited by this promise of intelligent explanation and disappointed when Anaxagoras often relied on mechanical causes instead.',
      'Leucippus and Democritus develop atomism: indivisible bodies move in void and form perceptible objects through arrangement and position. Atomism explains qualitative change through quantitative differences among underlying bodies and allows motion by affirming void against Eleatic objections. It also raises lasting questions. If all events arise through atoms and void, how do perception, value, and agency fit? Epicurus later modifies atomism to support an ethics aimed at freedom from fear.'
    ],['metaphysics','philosophy-of-science'],['empedocles','anaxagoras','leucippus','democritus','epicurus'],['Phaedo']),
    section('sophists','Sophists, rhetoric, and civic education',[
      'The sophists were diverse traveling intellectuals and teachers rather than members of one school. They became prominent in democratic cities where success in assemblies and courts depended on speech. Protagoras taught civic competence and is associated with the claim that the human being is the measure; Gorgias explored the force of language and offered radical arguments about being, knowledge, and communication. Other sophists analyzed law, nature, grammar, education, and political power.',
      'Their critics accuse them of teaching victory rather than truth and selling an appearance of wisdom. Plato’s dialogues make that charge philosophically powerful, but the polemic can obscure the sophists’ genuine questions. If customs differ across cities, are justice and piety natural or conventional? If citizens must judge matters beyond certain knowledge, what responsible role can rhetoric play? If language shapes how things appear, can education ever be neutral?',
      'The sophistic movement shifts attention toward human judgment, institutions, and the production of civic identity. Socrates shares this human focus while denying that persuasive success is equivalent to knowledge or virtue. Their encounter creates a recurring tension in Greek philosophy between reason and persuasion. Argument must be communicated through language and addressed to audiences, yet its validity cannot be reduced to whether it wins.'
    ],['political-philosophy','philosophy-of-language','epistemology'],['protagoras','gorgias','socrates'],['Protagoras','Gorgias']),
    section('socrates-plato','Socrates, Plato, and philosophy as ethical education',[
      'Socrates redirects philosophical attention toward examination of life, virtue, and claims to expertise, although natural and logical questions do not disappear. Because he writes nothing, his significance is inseparable from competing portraits. Plato presents him questioning definitions, exposing false confidence, and treating care of the soul as more important than external success. Xenophon emphasizes practical moral improvement, while Aristophanes turns him into a comic symbol of disruptive intellectual fashion.',
      'Plato transforms Socratic inquiry into a philosophical literature and establishes the Academy. His dialogues connect ethics to epistemology, metaphysics, psychology, education, and politics. The theory of Forms responds to the problem of how knowledge and judgment can answer to stable standards amid changing particulars. The Republic links justice in the soul to political organization and educational formation, while later dialogues criticize or complicate earlier proposals.',
      'The Socratic-Platonic turn changes what counts as philosophical success. A person may possess rhetorical power, wealth, or correct opinion while lacking an account of the good. Education must therefore shape desire and judgment rather than merely transfer information. This ideal can support intellectual humility and public accountability, but it can also support hierarchy if philosophers claim privileged authority. The tension between examination and expertise becomes part of Plato’s inheritance.'
    ],['ethics','platonism','epistemology','political-philosophy'],['socrates','plato'],['Apology','Meno','Republic']),
    section('aristotle','Aristotle and differentiated systematic inquiry',[
      'Aristotle studies in Plato’s Academy for roughly two decades before founding the Lyceum and developing a distinct approach. He rejects separate Forms as explanations of concrete substances while preserving form as an intelligible principle within things. His logic studies valid inference; physics studies change and natural beings; biology compares living structures; metaphysics asks about being, substance, cause, and actuality; ethics and politics study flourishing, character, institutions, and judgment.',
      'Aristotle’s systematic ambition is paired with methodological pluralism. Scientific demonstration, dialectical testing, empirical observation, rhetorical reasoning, and practical wisdom answer different kinds of questions. The four causes distinguish material, formal, efficient, and final explanation. Potentiality and actuality explain how change can be real without arising from absolute nonbeing. Hylomorphism explains living beings as organized composites rather than souls temporarily inhabiting bodies.',
      'His political and biological works also expose the limits of Greek philosophy. Aristotle naturalizes hierarchies of gender, labor, and slavery and restricts citizenship to a narrow group. These exclusions are not external to his concepts; they show how claims about nature and function can encode social power. Aristotle’s achievement and error both become part of later traditions that inherit his vocabulary.'
    ],['aristotelianism','logic','metaphysics','ethics'],['aristotle','plato'],['Metaphysics','Nicomachean Ethics','Politics']),
    section('hellenistic','Hellenistic schools and philosophy as a way of life',[
      'After the conquests of Alexander and the political transformations that followed, new schools developed systematic accounts of how to live under conditions not controlled by the citizen of a small polis. Cynics challenged convention through radical simplicity and frank speech. Epicureans connected atomist physics to freedom from fear, modest pleasure, and friendship. Stoics developed an integrated logic, physics, and ethics centered on virtue, rational judgment, nature, and cosmopolitan duty.',
      'Skeptical traditions questioned whether dogmatic claims could be justified. Pyrrhonists practiced suspension of judgment where opposing arguments remained balanced, seeking tranquility without asserting that knowledge was impossible. Academic skeptics developed critical methods within Plato’s institutional inheritance. These movements disagreed profoundly about nature, knowledge, and value, but each treated philosophy as training that should transform emotion, desire, attention, and action.',
      'The Hellenistic schools preserve and reorganize earlier arguments. Stoics inherit Socratic ethical independence and engage Heraclitean cosmology; Epicureans modify Democritean atomism; skeptics refine the challenge to certainty; Cynics radicalize the Socratic critique of external goods. Their practical writings remain accessible, but modern readers can misunderstand them when ethics is detached from the physics, logic, communities, and disciplined exercises that originally supported it.'
    ],['stoicism','epicureanism','skepticism','cynicism'],['epicurus','zeno','pyrrho','diogenes'],[]),
    section('roman-late-antique','Roman reception and late ancient transformation',[
      'Greek philosophy entered Roman intellectual life through education, translation, political encounter, and the movement of teachers. Cicero rendered Greek debates about ethics, knowledge, law, and rhetoric into Latin while comparing schools for Roman readers. Lucretius presented Epicurean physics and therapy in poetry. Seneca, Epictetus, and Marcus Aurelius developed Stoic practice around anger, grief, status, duty, and mortality. Roman reception was not passive preservation; it adapted Greek schools to new institutions and literary forms.',
      'Late antiquity saw intensive commentary and systematization. Platonists and Aristotelians studied canonical texts through organized curricula, while Neoplatonists such as Plotinus, Iamblichus, and Proclus transformed Platonic metaphysics into accounts of procession, hierarchy, and return. Commentators preserved arguments, clarified terminology, and framed questions inherited by later traditions. Boundaries between schools could remain polemical even as thinkers borrowed one another’s concepts.',
      'Christian intellectuals engaged Greek philosophy while criticizing pagan theology and reworking metaphysical concepts around creation, revelation, incarnation, and salvation. The resulting relationships ranged from rejection to deep synthesis. Ancient Greek philosophy survived not as an untouched archive but through communities that selected, translated, commented, argued, and connected it to new religious and political worlds.'
    ],['stoicism','neoplatonism','philosophy-of-religion'],['cicero','lucretius','seneca','epictetus','marcus-aurelius','plotinus','augustine'],[]),
    section('transmission','Transmission into Islamic, Jewish, Christian, Renaissance, and modern thought',[
      'Syriac and Arabic translation movements made Greek philosophical and scientific works available within Islamic intellectual cultures, often together with late ancient commentaries and texts whose authorship was misunderstood. Al-Farabi, Avicenna, Al-Ghazali, Averroes, and many others reconstructed questions about logic, intellect, causation, metaphysics, ethics, and revelation. Their work was not a bridge that merely carried Greek philosophy westward. It was a major philosophical tradition that transformed the inherited material and generated new disputes.',
      'Jewish and Christian philosophers likewise adapted Platonic and Aristotelian concepts to questions of creation, divine attributes, law, soul, and human fulfillment. Latin scholasticism developed through translations from Greek and Arabic and through commentarial methods shaped by ancient models. Renaissance humanists recovered and retranslated texts, while early modern philosophers defined new projects by criticizing scholastic Aristotelianism, reviving skepticism or atomism, and reconsidering mathematics and natural explanation.',
      'Modern philosophy continues to use ancient categories while changing their meaning. Virtue ethics returns to Aristotle; political theory rereads democracy, citizenship, and Plato’s Republic; logic and metaphysics revisit arguments about being, universals, and modality; philosophies of life recover Hellenistic practices. These receptions demonstrate that influence is not agreement. Ancient philosophy remains active because later thinkers repeatedly use it to formulate problems their own inherited vocabularies cannot settle.'
    ],['islamic-philosophy','medieval-scholasticism','philosophy-of-religion'],['al-farabi','avicenna','al-ghazali','averroes','aquinas'],[]),
    section('tensions','Recurring tensions across the tradition',[
      'The contrast between nature and convention organizes debates about law, morality, language, and political authority. If customs vary, are they merely local agreements, or can reason identify standards beyond them? Sophists, Socrates, Plato, Aristotle, Cynics, and Stoics answer differently. The contrast never becomes simple because appeals to nature can criticize arbitrary convention or falsely present hierarchy as inevitable.',
      'Being and becoming form another tension. Parmenides challenges the coherence of change; Heraclitus emphasizes ordered opposition; pluralists and atomists preserve unchanging constituents beneath rearrangement; Plato distinguishes Forms from changing particulars; Aristotle explains change through potentiality and actuality. Knowledge and opinion follow the same fault line: how can stable understanding arise from a world encountered through variable appearances?',
      'Ethics repeatedly contrasts virtue with conventional success. Socrates claims it is worse to commit injustice than suffer it. Plato asks whether justice benefits the person independent of reward. Aristotle connects flourishing to virtue while acknowledging external goods. Hellenistic schools seek forms of freedom less vulnerable to fortune. Alongside these arguments runs the tension between reason and persuasion. Philosophy needs language, teaching, and institutions, yet must distinguish accountable argument from the power to secure agreement.'
    ],['metaphysics','epistemology','ethics','political-philosophy'],['parmenides','heraclitus','socrates','plato','aristotle'],[]),
    section('reading','How to start reading ancient Greek philosophy',[
      'Begin with problems rather than attempting a chronological march through every fragment. Read a selection of Pre-Socratic fragments with commentary around change, being, and natural explanation. Because fragments are preserved through later authors, always distinguish the ancient words from the reporter’s framing. Pair Heraclitus and Parmenides to see why later accounts of reality must answer both becoming and stability. Read a sophist such as Gorgias or Protagoras through surviving texts and careful secondary guidance rather than only through Plato’s criticism.',
      'Move to Plato’s Apology, Euthyphro, Meno, and substantial books of the Republic. These show Socratic examination expanding into epistemology, psychology, and politics. Read Aristotle’s Nicomachean Ethics and Poetics before selected portions of De Anima, Physics, and Metaphysics. The shorter and more practical works reveal his method without pretending the technical texts are easy. Compare Plato and Aristotle on one problem, such as form, knowledge, or flourishing, rather than treating them as opposing personalities.',
      'Then read Hellenistic philosophy as systematic practice. Epictetus or Seneca should be connected to Stoic logic and physics; Epicurus’ letters should be connected to atomism; skeptical selections should be read as arguments and exercises rather than vague doubt. Throughout, remember that the archive is incomplete and later reception shapes what appears central. The goal is not to locate the moment reason replaced myth, but to follow a sustained, plural argument about how explanations and lives become answerable to criticism.'
    ],['ancient-greek','stoicism','epicureanism','skepticism'],['heraclitus','parmenides','socrates','plato','aristotle','epicurus','epictetus'],['Apology','Republic','Nicomachean Ethics'])
  ]
};
